     1	<!DOCTYPE html>
     2	<html lang="ko">
     3	<head>
     4	<meta charset="UTF-8">
     5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6	<title>EX Intelligence — 체계 구축 보고서</title>
     7	<link href="https://fonts.googleapis.com/css2?family=Noto+Serif+KR:wght@400;600;700&family=Noto+Sans+KR:wght@300;400;500;700&family=Playfair+Display:ital,wght@0,700;1,400&family=IBM+Plex+Mono:wght@400;600&display=swap" rel="stylesheet">
     8	<style>
     9	:root{
    10	  --ink:#1a1814;--ink2:#3d3a34;--ink3:#7a7570;--ink4:#b8b4ae;
    11	  --paper:#f8f6f1;--white:#ffffff;--surface:#f2efe8;--border:#e4e0d8;
    12	  --red:#c8102e;--red-dim:rgba(200,16,46,.08);
    13	  --green:#1a6b4a;--green-dim:rgba(26,107,74,.08);
    14	  --blue:#0f4c8a;--blue-dim:rgba(15,76,138,.08);
    15	  --amber:#b5650d;--amber-dim:rgba(181,101,13,.08);
    16	  --serif:'Playfair Display','Noto Serif KR',serif;
    17	  --body:'Noto Sans KR',sans-serif;
    18	  --mono:'IBM Plex Mono',monospace;
    19	}
    20	*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
    21	html{scroll-behavior:smooth;}
    22	body{font-family:var(--body);background:var(--paper);color:var(--ink);line-height:1.75;overflow-x:hidden;}
    23	
    24	#progress{position:fixed;top:0;left:0;height:3px;background:var(--red);z-index:999;width:0;transition:width .1s linear;box-shadow:0 0 6px rgba(200,16,46,.4);}
    25	
    26	.nav{position:fixed;top:0;left:0;right:0;z-index:100;height:52px;background:rgba(248,246,241,.96);backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;padding:0 48px;}
    27	.nav-brand{font-family:var(--mono);font-size:12px;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:var(--ink2);display:flex;align-items:center;gap:8px;}
    28	.nav-dot{width:7px;height:7px;background:var(--red);border-radius:50%;}
    29	.nav-links{display:flex;gap:0;list-style:none;}
    30	.nav-links a{display:block;padding:6px 12px;font-size:11px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;color:var(--ink3);text-decoration:none;border-radius:3px;transition:color .15s,background .15s;}
    31	.nav-links a:hover{color:var(--ink);background:var(--surface);}
    32	.nav-links a.active{color:var(--red);}
    33	.nav-meta{font-family:var(--mono);font-size:11px;color:var(--ink4);}
    34	
    35	/* HERO */
    36	.hero{min-height:100vh;display:flex;flex-direction:column;justify-content:flex-end;padding:120px 48px 80px;position:relative;overflow:hidden;background:var(--ink);}
    37	.hero-lines{position:absolute;inset:0;background-image:repeating-linear-gradient(0deg,transparent,transparent 59px,rgba(255,255,255,.025) 60px);pointer-events:none;}
    38	.hero-glow{position:absolute;top:-120px;left:-120px;width:700px;height:700px;background:radial-gradient(circle,rgba(200,16,46,.13) 0%,transparent 65%);pointer-events:none;animation:breathe 8s ease-in-out infinite alternate;}
    39	@keyframes breathe{from{opacity:.6;transform:scale(1);}to{opacity:1;transform:scale(1.08);}}
    40	.hero-eyebrow{font-family:var(--mono);font-size:11px;color:rgba(200,16,46,.85);letter-spacing:.2em;text-transform:uppercase;margin-bottom:28px;display:flex;align-items:center;gap:12px;}
    41	.hero-eyebrow::before{content:'';width:32px;height:1px;background:var(--red);}
    42	.hero-h1{font-family:var(--serif);font-size:clamp(52px,8.5vw,112px);font-weight:700;line-height:.92;letter-spacing:-.01em;color:#f8f6f1;margin-bottom:8px;}
    43	.hero-h1 .r{color:var(--red);}
    44	.hero-sub{font-family:var(--serif);font-size:clamp(18px,2.8vw,34px);font-weight:400;font-style:italic;color:rgba(248,246,241,.45);margin-bottom:52px;}
    45	.hero-kpis{display:flex;gap:48px;flex-wrap:wrap;border-top:1px solid rgba(255,255,255,.1);padding-top:32px;}
    46	.kpi{display:flex;flex-direction:column;gap:4px;}
    47	.kpi-n{font-family:var(--serif);font-size:42px;font-weight:700;line-height:1;color:var(--red);}
    48	.kpi-l{font-size:11px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:rgba(248,246,241,.35);}
    49	.hero-idx{position:absolute;right:48px;bottom:80px;display:flex;flex-direction:column;gap:14px;}
    50	.hi{display:flex;align-items:center;gap:10px;cursor:pointer;text-decoration:none;opacity:.3;transition:opacity .2s;}
    51	.hi:hover{opacity:1;}
    52	.hi-n{font-family:var(--mono);font-size:10px;color:var(--ink4);width:20px;text-align:right;}
    53	.hi-l{width:20px;height:1px;background:rgba(248,246,241,.25);transition:width .2s,background .2s;}
    54	.hi:hover .hi-l{width:36px;background:var(--red);}
    55	.hi-t{font-size:11px;font-weight:700;color:rgba(248,246,241,.55);letter-spacing:.04em;}
    56	.hero-scroll{position:absolute;bottom:38px;left:48px;font-family:var(--mono);font-size:10px;letter-spacing:.14em;text-transform:uppercase;color:rgba(248,246,241,.28);display:flex;align-items:center;gap:10px;animation:bob 2.5s ease-in-out infinite;}
    57	.hero-scroll::after{content:'↓';font-size:16px;}
    58	@keyframes bob{0%,100%{transform:translateY(0);}50%{transform:translateY(7px);}}
    59	
    60	/* SECTIONS */
    61	section{padding:96px 48px;border-bottom:1px solid var(--border);opacity:0;transform:translateY(20px);transition:opacity .65s ease,transform .65s ease;}
    62	section.vis{opacity:1;transform:translateY(0);}
    63	section:nth-child(odd){background:var(--white);}
    64	section:nth-child(even){background:var(--paper);}
    65	.sec-ey{font-family:var(--mono);font-size:10px;font-weight:600;letter-spacing:.16em;text-transform:uppercase;color:var(--red);margin-bottom:12px;display:flex;align-items:center;gap:8px;}
    66	.sec-ey .en{color:var(--ink4);}
    67	.sec-h1{font-family:var(--serif);font-size:clamp(30px,4.5vw,56px);font-weight:700;line-height:1.05;color:var(--ink);margin-bottom:14px;}
    68	.sec-is{font-size:15px;font-style:italic;color:var(--ink3);margin-bottom:48px;max-width:680px;line-height:1.7;}
    69	.sec-h2{font-family:var(--serif);font-size:25px;font-weight:700;color:var(--ink);margin:44px 0 14px;}
    70	.sec-h3{font-size:14px;font-weight:700;color:var(--red);letter-spacing:.02em;margin:28px 0 8px;display:flex;align-items:center;gap:8px;}
    71	.sec-h3::before{content:'';width:14px;height:2px;background:var(--red);}
    72	p.b{font-size:15px;color:var(--ink2);line-height:1.85;margin-bottom:20px;max-width:720px;}
    73	p.b strong{color:var(--ink);font-weight:700;}
    74	.cit{font-family:var(--mono);font-size:11px;color:var(--ink4);margin:-6px 0 20px 0;padding-left:14px;border-left:2px solid var(--border);}
    75	
    76	/* PULLQUOTE */
    77	.pq{font-family:var(--serif);font-size:clamp(17px,2.2vw,24px);font-weight:700;font-style:italic;color:var(--red);line-height:1.5;padding:28px 0 28px 24px;border-left:5px solid var(--red);margin:36px 0;max-width:680px;}
    78	
    79	/* DATA BOX */
    80	.dbox{background:#fdf8f8;border:1px solid rgba(200,16,46,.14);border-left:5px solid var(--red);border-radius:0 6px 6px 0;padding:22px 26px;margin:28px 0;max-width:760px;}
    81	.dbox-l{font-family:var(--mono);font-size:10px;font-weight:600;letter-spacing:.14em;text-transform:uppercase;color:var(--red);margin-bottom:12px;}
    82	.dbox ul{list-style:none;display:flex;flex-direction:column;gap:7px;}
    83	.dbox li{font-size:13px;color:var(--ink2);line-height:1.6;padding-left:16px;position:relative;}
    84	.dbox li::before{content:'';position:absolute;left:0;top:8px;width:5px;height:5px;background:var(--red);border-radius:50%;}
    85	
    86	/* TABLE */
    87	.tc{width:100%;border-collapse:collapse;margin:20px 0;font-size:13px;max-width:760px;}
    88	.tc th{background:var(--ink);color:#fff;padding:10px 16px;text-align:left;font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;}
    89	.tc td{padding:12px 16px;border-bottom:1px solid var(--border);vertical-align:top;color:var(--ink2);line-height:1.55;}
    90	.tc td:first-child{font-weight:700;color:var(--ink);white-space:nowrap;background:var(--surface);}
    91	.tc tr:hover td{background:rgba(200,16,46,.02);}
    92	
    93	/* BEFORE/AFTER */
    94	.ba{display:grid;grid-template-columns:1fr 28px 1fr;gap:0;max-width:760px;margin:16px 0 8px;align-items:stretch;}
    95	.ba-c{border-radius:6px;overflow:hidden;}
    96	.ba-c.bef{border:1px solid var(--border);}
    97	.ba-c.aft{border:1px solid rgba(26,107,74,.25);}
    98	.ba-h{padding:8px 14px;font-family:var(--mono);font-size:10px;font-weight:600;letter-spacing:.12em;text-transform:uppercase;}
    99	.ba-c.bef .ba-h{background:var(--surface);color:var(--ink3);}
   100	.ba-c.aft .ba-h{background:rgba(26,107,74,.08);color:var(--green);}
   101	.ba-b{padding:14px 16px;font-size:13px;color:var(--ink2);line-height:1.6;background:var(--white);}
   102	.ba-arr{display:flex;align-items:center;justify-content:center;color:var(--red);font-size:20px;font-weight:900;}
   103	.ba-res{max-width:760px;margin-bottom:28px;padding:10px 14px;background:rgba(26,107,74,.06);border:1px solid rgba(26,107,74,.15);border-radius:4px;font-size:12px;font-family:var(--mono);color:var(--green);}
   104	
   105	/* LAYER FLOW */
   106	.lflow{max-width:760px;display:flex;flex-direction:column;gap:0;}
   107	.lblock{border:1px solid var(--border);border-radius:8px;overflow:hidden;margin-bottom:4px;}
   108	.lhead{padding:11px 18px;font-size:11px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;display:flex;align-items:center;gap:8px;border-bottom:1px solid var(--border);}
