function renderRefs(data, containerId){
  const c=document.getElementById(containerId);
  data.forEach(r=>{
    const d=document.createElement('div');
    d.className='ref-item';
    d.innerHTML=`<div class="ref-num">${r.num}</div><div class="ref-content"><div class="ref-title">${r.title}</div><div class="ref-desc">${r.desc}</div>${r.links.map(l=>`<div class="ref-url"><span class="ref-url-l">${l.l}</span><a href="${l.u}" target="_blank" style="color:var(--blue);text-decoration:none;">${l.u}</a></div>`).join('')}</div>`;
    c.appendChild(d);
  });
}
