     3	<head>
     4	<meta charset="UTF-8">
     5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6	<title>EX Intelligence — LG PRI EXG팀 2026</title>
     7	<link rel="preconnect" href="https://fonts.googleapis.com">
     8	<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;600;700&display=swap" rel="stylesheet">
     9	<style>
    10	
    11	/* ─────────────────────────────────────────────
    12	   LG CHO 포털 빌더 스킬 — 디자인 토큰
    13	   Primary: #A50034 (LG Red)
    14	   Structure: top-bar / hero / main 3단
    15	   Font: Noto Sans KR 전용
    16	───────────────────────────────────────────── */
    17	:root {
    18	  --lg-red:      #A50034;
    19	  --lg-red-dk:   #7A0026;
    20	  --lg-red-lt:   #F9E6EC;
    21	  --lg-red-md:   #D4004A;
    22	  --dark:        #1C1917;
    23	  --dark2:       #2D2926;
