}

/* ── THEORY GRID ── */
.theory-matrix {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  margin: 24px 0;
}
.th-card {
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-md);
  padding: 16px;
  background: var(--white);
  box-shadow: var(--shadow-sm);
}
.th-abbr {
  font-size: 10px; font-weight: 600;
  letter-spacing: 1.5px; color: var(--lg-red);
