  display: inline-block; margin-bottom: 8px;
}
.th-name { font-size: 14px; font-weight: 700; color: var(--dark); margin-bottom: 2px; }
.th-scholar { font-size: 11px; color: var(--gray-2); margin-bottom: 8px; }
.th-stat { font-size: 12px; font-weight: 600; color: var(--lg-red); margin-bottom: 8px; }
.th-apply { font-size: 12.5px; line-height: 1.65; color: var(--gray-1); }

/* ── MILESTONE ── */
.milestone {
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin: 24px 0;
  background: var(--white);
  box-shadow: var(--shadow-sm);
}
.ms-row {
  display: grid;
  grid-template-columns: 110px 1fr;
}
.ms-row + .ms-row { border-top: 1px solid var(--gray-4); }
.ms-tag {
  padding: 18px 14px;
  background: var(--dark);
