  padding-left: 16px; position: relative;
}
.theory-body li::before { content: '◆'; position: absolute; left: 0; color: #1D6A4A; font-size: 9px; top: 4px; }
.theory-body li strong { color: #C0EAD8; font-weight: 600; }

/* ── DBOX (레드 액센트 리스트) ── */
.dbox {
  margin: 20px 0; padding: 16px 20px;
  border: 1px solid rgba(165,0,52,.15);
  border-left: 3px solid var(--lg-red);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  background: var(--white);
}
.dbox.ds-dbox {
  border-color: rgba(91,45,142,.15);
  border-left-color: var(--ds-purple-md);
  background: var(--ds-purple-lt);
}
.dbox-label {
  font-size: 10px; font-weight: 600;
  letter-spacing: 1.5px; color: var(--lg-red);
  margin-bottom: 10px;
}
.ds-dbox .dbox-label { color: var(--ds-purple); }
.dbox ul { list-style: none; display: flex; flex-direction: column; gap: 6px; }
.dbox li {
  font-size: 13px; line-height: 1.75;
  color: var(--charcoal);
  padding-left: 14px; position: relative;
}
.dbox li::before { content: '•'; position: absolute; left: 2px; color: var(--lg-red); }
.ds-dbox li::before { color: var(--ds-purple-md); }
.dbox li strong { font-weight: 600; color: var(--dark); }

/* ── KPI STRIP ── */
.kpi-strip {
  display: grid; grid-template-columns: repeat(4, 1fr);
  border: 1px solid var(--gray-4); border-radius: var(--radius-lg);
  overflow: hidden; margin: 28px 0;
  background: var(--white); box-shadow: var(--shadow-sm);
}
.kpi-item {
  padding: 20px 16px;
  border-right: 1px solid var(--gray-4);
  text-align: center;
}
.kpi-item:last-child { border-right: none; }
.kpi-num {
  display: block; font-size: 26px; font-weight: 700;
  color: var(--lg-red); letter-spacing: -0.5px;
  line-height: 1.2; margin-bottom: 4px;
}
.kpi-label { font-size: 11px; color: var(--gray-1); line-height: 1.45; font-weight: 400; }

/* ── DATA SENSING LAYER CARDS ── */
.ds-layer-grid {
  display: flex; flex-direction: column;
  gap: 4px; margin: 28px 0;
}
.ds-layer-card {
  border-radius: var(--radius-md);
  border: 1px solid rgba(91,45,142,.2);
  overflow: hidden;
}
.ds-layer-head {
  padding: 13px 18px;
  display: flex; align-items: center; gap: 12px;
  border-bottom: 1px solid rgba(91,45,142,.12);
}
.ds-layer-head.dl1 { background: linear-gradient(135deg, rgba(91,45,142,.18), rgba(91,45,142,.08)); }
.ds-layer-head.dl2 { background: linear-gradient(135deg, rgba(13,115,119,.18), rgba(13,115,119,.08)); }
.ds-layer-head.dl3 { background: linear-gradient(135deg, rgba(181,101,13,.18), rgba(181,101,13,.08)); }
.ds-layer-num {
  font-size: 28px; font-weight: 700; line-height: 1;
  opacity: .18; font-family: serif;
}
.dl1 .ds-layer-num { color: var(--ds-purple); }
.dl2 .ds-layer-num { color: var(--ds-teal); }
.dl3 .ds-layer-num { color: var(--ds-amber); }
.ds-layer-meta { flex: 1; }
.ds-layer-badge {
  font-size: 9px; font-weight: 600; letter-spacing: 1.5px;
  margin-bottom: 2px; display: block;
}
.dl1 .ds-layer-badge { color: var(--ds-purple-md); }
.dl2 .ds-layer-badge { color: var(--ds-teal); }
.dl3 .ds-layer-badge { color: var(--ds-amber); }
.ds-layer-title { font-size: 14px; font-weight: 700; color: var(--dark); }
.dl1 .ds-layer-title { color: var(--ds-purple-dk); }
.dl2 .ds-layer-title { color: #084D50; }
.dl3 .ds-layer-title { color: #7A4000; }
.ds-layer-body {
  padding: 14px 18px; background: var(--white);
  display: flex; gap: 16px; align-items: flex-start;
}
.ds-tags { display: flex; flex-wrap: wrap; gap: 5px; flex-shrink: 0; max-width: 280px; }
.ds-tag {
  font-size: 11px; padding: 3px 9px;
  border-radius: 3px; font-weight: 500;
}
.dl1-tag { background: var(--ds-purple-lt); border: 1px solid rgba(91,45,142,.2); color: var(--ds-purple); }
.dl2-tag { background: var(--ds-teal-lt); border: 1px solid rgba(13,115,119,.2); color: var(--ds-teal); }
.dl3-tag { background: var(--ds-amber-lt); border: 1px solid rgba(181,101,13,.2); color: var(--ds-amber); }
.ds-layer-desc { font-size: 13px; color: var(--gray-1); line-height: 1.7; }
.ds-conn {
  text-align: center; padding: 2px 0;
  color: var(--ds-purple-md); font-weight: 700; font-size: 13px;
  display: flex; align-items: center; justify-content: center; gap: 10px;
}
.ds-conn::before, .ds-conn::after {
  content: ''; flex: 1; height: 1px;
  background: linear-gradient(to right, transparent, rgba(91,45,142,.15));
}
.ds-conn::after { background: linear-gradient(to left, transparent, rgba(91,45,142,.15)); }

/* ── FUSION ENGINE ── */
.fusion-box {
  margin: 24px 0; border: 2px solid var(--ds-purple-md);
  border-radius: var(--radius-lg); overflow: hidden;
}
.fusion-head {
  background: var(--ds-purple); padding: 14px 22px;
  display: flex; align-items: center; gap: 10px;
}
.fusion-title {
  font-size: 12px; font-weight: 600; letter-spacing: 2px;
  color: rgba(255,255,255,.9);
}
.fusion-sub { font-size: 11px; color: rgba(255,255,255,.45); margin-left: auto; }
.fusion-body { background: var(--white); padding: 18px 22px; }
.fusion-rules { display: flex; flex-direction: column; gap: 10px; }
.fusion-rule {
  display: flex; gap: 12px; align-items: flex-start;
  padding: 11px 14px;
  background: var(--ds-purple-lt);
  border: 1px solid rgba(91,45,142,.12);
  border-radius: var(--radius-sm);
}
.fusion-rule-num {
  font-size: 10px; font-weight: 700;
  color: var(--ds-purple-md); flex-shrink: 0;
  width: 20px; padding-top: 2px;
}
.fusion-rule-text { font-size: 13px; color: var(--charcoal); line-height: 1.65; }
.fusion-rule-text strong { color: var(--dark); font-weight: 600; }

/* ── ETHICS BOX ── */
.ethics-box {
  margin: 24px 0;
  border: 1px solid rgba(181,101,13,.3);
  border-left: 4px solid var(--ds-amber);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  background: var(--ds-amber-lt);
  padding: 16px 20px;
}
.ethics-label {
  font-size: 10px; font-weight: 600; letter-spacing: 2px;
  color: var(--ds-amber); margin-bottom: 8px;
  display: flex; align-items: center; gap: 6px;
}
.ethics-label::before { content: '⚖'; font-size: 12px; }
.ethics-body { font-size: 13px; color: #5C3A00; line-height: 1.7; }
.ethics-body strong { color: #3A2200; }

/* ── PHASE ROADMAP ── */
.ds-phase-grid {
  display: grid; grid-template-columns: repeat(3, 1fr);
  gap: 14px; margin: 24px 0;
}
.ds-phase {
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-md);
  overflow: hidden; background: var(--white);
  box-shadow: var(--shadow-sm);
}
.ds-phase-head {
  padding: 12px 16px;
  border-bottom: 1px solid var(--gray-4);
}
.ds-phase-head.p1 { background: var(--ds-purple-lt); border-bottom-color: rgba(91,45,142,.2); }
.ds-phase-head.p2 { background: var(--ds-teal-lt);   border-bottom-color: rgba(13,115,119,.2); }
.ds-phase-head.p3 { background: var(--ds-amber-lt);  border-bottom-color: rgba(181,101,13,.2); }
.ds-phase-tag {
  font-size: 9px; font-weight: 600; letter-spacing: 1.5px;
  margin-bottom: 3px;
}
.p1 .ds-phase-tag { color: var(--ds-purple); }
.p2 .ds-phase-tag { color: var(--ds-teal); }
.p3 .ds-phase-tag { color: var(--ds-amber); }
.ds-phase-name { font-size: 13px; font-weight: 700; color: var(--dark); }
.ds-phase-period { font-size: 10px; color: var(--gray-2); margin-top: 1px; }
.ds-phase-body { padding: 14px 16px; }
.ds-phase-body ul { list-style: none; display: flex; flex-direction: column; gap: 5px; }
.ds-phase-body li { font-size: 12px; line-height: 1.65; color: var(--gray-1); padding-left: 12px; position: relative; }
.ds-phase-body li::before { content: '→'; position: absolute; left: 0; color: var(--gray-3); font-size: 10px; }

/* ── 3-TIER GRID ── */
.tier-grid {
  display: grid; grid-template-columns: repeat(3, 1fr);
  gap: 16px; margin: 28px 0;
}
.tier-card {
  border-radius: var(--radius-lg);
  border: 1px solid var(--gray-4);
  background: var(--white);
  overflow: hidden; box-shadow: var(--shadow-sm);
}
.tier-head { padding: 14px 16px 12px; }
.tier-card.leader .tier-head { background: #1A2C58; border-bottom: 2px solid #3A5A9A; }
.tier-card.exec   .tier-head { background: var(--dark); border-bottom: 2px solid var(--lg-red); }
.tier-card.hr     .tier-head { background: #0A2A1A; border-bottom: 2px solid #1D6A4A; }
.tier-role { font-size: 13px; font-weight: 700; color: #F5F3F0; margin-bottom: 2px; }
.tier-cia  { font-size: 10px; color: rgba(245,243,240,.4); font-weight: 400; }
.tier-body { padding: 16px; }
.tier-q {
  font-size: 14px; font-weight: 700;
  margin-bottom: 10px; padding-bottom: 10px;
  border-bottom: 1px dashed var(--gray-4);
}
.tier-card.leader .tier-q { color: #1A2C58; }
.tier-card.exec   .tier-q { color: var(--lg-red-dk); }
.tier-card.hr     .tier-q { color: #085041; }
.tier-section { margin-bottom: 10px; }
.tier-section-label {
  font-size: 9px; font-weight: 600;
  letter-spacing: 1.5px; margin-bottom: 5px;
}
.tier-card.leader .tier-section-label { color: #3A5A9A; }
.tier-card.exec   .tier-section-label { color: var(--lg-red); }
.tier-card.hr     .tier-section-label { color: #1D6A4A; }
.tier-text { font-size: 12.5px; line-height: 1.65; color: var(--gray-1); }
.tier-stat {
  font-size: 11px; line-height: 1.5;
  color: var(--gray-2); font-style: italic;
  padding: 8px 10px; background: var(--gray-5);
  border-radius: var(--radius-sm); margin-top: 10px;
}

/* ── 3-LAYER FLOW ── */
.layer-flow {
  display: grid; grid-template-columns: 1fr auto 1fr auto 1fr;
  align-items: stretch; gap: 0; margin: 24px 0;
}
.layer-card {
  border-radius: var(--radius-md);
  padding: 18px 16px; border: 1px solid var(--gray-4);
}
.layer-card.l1 { background: #F0FAF6; border-color: rgba(29,106,74,.3); }
.layer-card.l2 { background: #F0F4FB; border-color: rgba(58,106,170,.3); }
.layer-card.l3 { background: var(--lg-red-lt); border-color: rgba(165,0,52,.25); }
.layer-tag { font-size: 9.5px; font-weight: 600; letter-spacing: 1.5px; margin-bottom: 6px; }
.layer-card.l1 .layer-tag { color: #1D6A4A; }
.layer-card.l2 .layer-tag { color: #3A5A9A; }
.layer-card.l3 .layer-tag { color: var(--lg-red); }
.layer-title { font-size: 14px; font-weight: 700; margin-bottom: 6px; }
.layer-card.l1 .layer-title { color: #085041; }
.layer-card.l2 .layer-title { color: #1A2C58; }
.layer-card.l3 .layer-title { color: var(--lg-red-dk); }
.layer-desc { font-size: 12px; line-height: 1.65; color: var(--gray-1); }
.layer-arr {
  display: flex; align-items: center;
  padding: 0 10px; color: var(--gray-3);
  font-size: 18px; font-weight: 300;
}

/* ── THEORY GRID ── */
.theory-matrix {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 14px; margin: 24px 0;
}
.th-card {
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-md);
  padding: 16px; background: var(--white);
  box-shadow: var(--shadow-sm);
}
.th-abbr {
  font-size: 10px; font-weight: 600;
  letter-spacing: 1.5px; color: var(--lg-red);
  background: var(--lg-red-lt);
  padding: 2px 7px; border-radius: 3px;
  display: inline-block; margin-bottom: 8px;
}
.th-name { font-size: 14px; font-weight: 700; color: var(--dark); margin-bottom: 2px; }
.th-scholar { font-size: 11px; color: var(--gray-2); margin-bottom: 8px; }
.th-stat { font-size: 12px; font-weight: 600; color: var(--lg-red); margin-bottom: 8px; }
.th-apply { font-size: 12.5px; line-height: 1.65; color: var(--gray-1); }

/* ── MILESTONE ── */
.milestone {
  border: 1px solid var(--gray-4); border-radius: var(--radius-lg);
  overflow: hidden; margin: 24px 0;
  background: var(--white); box-shadow: var(--shadow-sm);
}
.ms-row { display: grid; grid-template-columns: 110px 1fr; }
.ms-row + .ms-row { border-top: 1px solid var(--gray-4); }
.ms-tag {
  padding: 18px 14px; background: var(--dark);
  display: flex; flex-direction: column;
  justify-content: center; gap: 3px;
  border-right: 3px solid var(--lg-red);
}
.ms-tag.ds-ms { border-right-color: var(--ds-purple-md); }
.ms-m { font-size: 9.5px; font-weight: 500; color: rgba(245,243,240,.3); letter-spacing: 1px; }
.ms-date { font-size: 13px; font-weight: 700; color: #F5F3F0; }
.ms-body { padding: 16px 18px; }
.ms-title { font-size: 13.5px; font-weight: 700; color: var(--dark); margin-bottom: 5px; }
.ms-desc { font-size: 12.5px; line-height: 1.7; color: var(--gray-1); }

/* ── FAQ ── */
.faq-item { padding: 20px 0; border-bottom: 1px solid var(--gray-4); }
.faq-item:last-child { border-bottom: none; }
.faq-q {
  font-size: 15px; font-weight: 700; color: var(--dark);
  margin-bottom: 8px; padding-left: 20px; position: relative;
}
.faq-q::before {
  content: 'Q'; position: absolute; left: 0;
  color: var(--lg-red); font-size: 13px; font-weight: 700;
  background: var(--lg-red-lt);
  width: 18px; height: 18px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 3px; top: 2px; line-height: 1; text-indent: 0;
}
.faq-a { font-size: 14px; line-height: 1.85; color: var(--charcoal); }

/* ── PRESS RELEASE CARD ── */
.press-card {
  background: var(--white); border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  padding: 28px 32px; margin: 28px 0;
  box-shadow: var(--shadow-md);
}
.press-date { font-size: 10px; font-weight: 600; letter-spacing: 2px; color: var(--gray-2); margin-bottom: 12px; }
.press-title { font-size: 22px; font-weight: 700; color: var(--dark); line-height: 1.35; margin-bottom: 6px; letter-spacing: -0.3px; }
.press-subtitle { font-size: 13px; color: var(--gray-2); margin-bottom: 18px; }
.press-body { font-size: 14px; line-height: 1.85; color: var(--charcoal); }
.press-highlight {
  margin-top: 18px; padding: 14px 18px;
  border-left: 3px solid var(--lg-red);
  background: var(--lg-red-lt);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}
.press-highlight p { font-size: 14.5px; font-weight: 500; color: var(--lg-red-dk); line-height: 1.65; }

/* ── CLOSING ── */
.closing { background: var(--dark); padding: 80px 0 60px; }
.closing .section-wrap { text-align: center; }
.close-eyebrow { font-size: 10px; font-weight: 600; letter-spacing: 3px; color: rgba(245,243,240,.2); margin-bottom: 20px; }
.close-title { font-size: clamp(26px, 3.5vw, 42px); font-weight: 700; color: #F5F3F0; line-height: 1.25; margin-bottom: 24px; letter-spacing: -0.5px; }
.close-body { font-size: 14px; line-height: 1.9; color: rgba(245,243,240,.48); max-width: 540px; margin: 0 auto 16px; }
.close-quote { font-size: 17px; font-weight: 500; color: rgba(165,0,52,.7); margin-top: 36px; line-height: 1.6; }

/* ── FOOTER ── */
footer {
  background: var(--charcoal); padding: 20px 40px;
  display: flex; align-items: center; justify-content: space-between;
  border-top: 1px solid rgba(255,255,255,.04);
}
footer span { font-size: 11px; color: rgba(255,255,255,.22); font-weight: 400; }

/* ── DIVIDER ── */
.divider { height: 1px; background: var(--line); margin: 40px 0; }

/* ── NEW BADGE ── */
.new-tag {
  display: inline-block; font-size: 8px; font-weight: 600;
  letter-spacing: 1px; background: #FFD700; color: #5A3A00;
  padding: 1px 6px; border-radius: 3px;
  margin-left: 6px; vertical-align: middle;
}

/* ── REVEAL ── */
.reveal {
  opacity: 0; transform: translateY(16px);
  transition: opacity .55s ease, transform .55s ease;
}
.reveal.visible { opacity: 1; transform: translateY(0); }

@media(max-width: 768px) {
  nav { padding: 0 16px; }
  .nav-links { display: none; }
  .hero { padding: 72px 24px 48px; min-height: auto; }
  .section-wrap { padding: 52px 20px; }
  .tier-grid, .theory-matrix, .ds-phase-grid { grid-template-columns: 1fr; }
  .kpi-strip { grid-template-columns: 1fr 1fr; }
  .layer-flow { grid-template-columns: 1fr; }
  .layer-arr { display: none; }
  .ds-layer-body { flex-direction: column; }
  .ds-tags { max-width: 100%; }
  .hero-kpi { flex-wrap: wrap; gap: 0; }
  footer { flex-direction: column; gap: 4px; text-align: center; }
}
</style>
