.ds-phase-head.p2 { background: var(--ds-teal-lt);   border-bottom-color: rgba(13,115,119,.2); }
.ds-phase-head.p3 { background: var(--ds-amber-lt);  border-bottom-color: rgba(181,101,13,.2); }
